  template <bool DO_AREA>
  void tech_map_impl<Ntk, CutSize, CutData, NInputs, Configuration>::match_phase(node<Ntk> const &n, uint8_t phase) {
    // Simulated annealing parameters
    static double temperature = 100.0;
    static const double cooling_rate = 0.97;
    static int iteration = 0;

    double best_arrival = std::numeric_limits<double>::max();
    double best_area_flow = std::numeric_limits<double>::max();
    float best_area = std::numeric_limits<float>::max();
    uint32_t best_size = UINT32_MAX;
    uint8_t best_cut = 0u;
    uint8_t best_phase = 0u;
    uint8_t cut_index = 0u;
    auto index = ntk.node_to_index(n);

    auto &node_data = node_match[index];
    auto &cut_matches = matches[index];
    supergate<NInputs> const *best_supergate = node_data.best_supergate[phase];

    /* recompute best match info */
    if (best_supergate != nullptr) {
      auto const &cut = cuts.cuts(index)[node_data.best_cut[phase]];

      best_phase = node_data.phase[phase];
      best_arrival = 0.0f;
      best_area_flow = best_supergate->area + cut_leaves_flow(cut, n, phase);
      best_area = best_supergate->area;
      best_cut = node_data.best_cut[phase];
      best_size = cut.size();

      auto ctr = 0u;
      for (auto l : cut) {
        double arrival_pin = node_match[l].arrival[(best_phase >> ctr) & 1] + best_supergate->tdelay[ctr];
        best_arrival = std::max(best_arrival, arrival_pin);
        ++ctr;
      }
    }

    /* foreach cut with stagnation detection */
    static int stagnation_count = 0;
    static const int max_stagnation = 50;

    // Check for stagnation
    if (best_arrival >= node_data.arrival[phase] - epsilon && 
        best_area_flow >= node_data.flows[phase] - epsilon) {
        stagnation_count++;
        if (stagnation_count > max_stagnation) {
            // Force exploration by resetting best values
            best_arrival = std::numeric_limits<double>::max();
            best_area_flow = std::numeric_limits<double>::max();
            stagnation_count = 0;
        }
    } else {
        stagnation_count = 0;
    }

    for (auto &cut : cuts.cuts(index)) {
      /* trivial cuts or not matched cuts */
      if ((*cut)->data.ignore) {
        ++cut_index;
        continue;
      }

      auto const &supergates = cut_matches[(*cut)->data.match_index].supergates;
      auto const negation = cut_matches[(*cut)->data.match_index].negations[phase];

      if (supergates[phase] == nullptr) {
        ++cut_index;
        continue;
      }

      /* match each gate and take the best one */
      for (auto const &gate : *supergates[phase]) {
        uint8_t gate_polarity = gate.polarity ^ negation;
        node_data.phase[phase] = gate_polarity;
        double area_local = gate.area + cut_leaves_flow(*cut, n, phase);
        double worst_arrival = 0.0f;

        auto ctr = 0u;
        for (auto l : *cut) {
          double arrival_pin = node_match[l].arrival[(gate_polarity >> ctr) & 1] + gate.tdelay[ctr];
          worst_arrival = std::max(worst_arrival, arrival_pin);
          ++ctr;
        }

        if constexpr (DO_AREA) {
          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        bool accept = compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size);
        if (!accept && temperature > 0.1) {
            // Normalized probabilistic acceptance considering both objectives
            double arrival_norm = (worst_arrival - best_arrival) / (best_arrival + epsilon);
            double area_norm = (area_local - best_area_flow) / (best_area_flow + epsilon);
            double delta = sqrt(arrival_norm*arrival_norm + area_norm*area_norm);

            // Adaptive probability scaling based on temperature
            double prob_scale = 1.0 + 10.0 * (1.0 - temperature/100.0);
            accept = (rand() / static_cast<double>(RAND_MAX)) < 
                   prob_scale * exp(-delta / temperature);
        }

        if (accept) {
            best_arrival = worst_arrival;
            best_area_flow = area_local;
            best_size = cut->size();
            best_cut = cut_index;
            best_area = gate.area;
            best_phase = gate_polarity;
            best_supergate = &gate;
        }
      }

      ++cut_index;
    }

    node_data.flows[phase] = best_area_flow;
    node_data.arrival[phase] = best_arrival;
    node_data.area[phase] = best_area;
    node_data.best_cut[phase] = best_cut;
    node_data.phase[phase] = best_phase;
    node_data.best_supergate[phase] = best_supergate;

    // Adaptive cooling based on solution improvement
    static double last_best_arrival = std::numeric_limits<double>::max();
    static double last_best_area = std::numeric_limits<double>::max();
    iteration++;

    // Calculate improvement from last iteration
    double arrival_improvement = last_best_arrival - best_arrival;
    double area_improvement = last_best_area - best_area_flow;

    // More aggressive cooling if we're making progress
    if (arrival_improvement > epsilon || area_improvement > epsilon) {
        temperature *= 0.95; // Faster cooling when improving
    } else {
        temperature *= 0.99; // Slower cooling when stagnant
    }

    // Reset temperature if we're stuck
    if (iteration % 100 == 0 && 
        (arrival_improvement < epsilon && area_improvement < epsilon)) {
        temperature = 100.0; // Reset to maintain exploration
    }

    last_best_arrival = best_arrival;
    last_best_area = best_area_flow;
    }
